// =========================================
// تحديد مصدر الطلب وإعداد الموضوع
// =========================================

const inputData = $input.item.json;

// إذا جاء من تيليجرام — نسحب نص رسالة صالح
const telegramText = inputData?.message?.text || inputData?.text || null;

// إذا جاء من جدولة أو يدوي — موضوع افتراضي
const defaultTopic = 'مراجعة أسبوعية: تقييم حالة النظام وفرص التحسين وأي أولويات تشغيلية مستجدة';

const topic = telegramText && !telegramText.startsWith('/') ? telegramText : defaultTopic;

const isScheduled = !telegramText;
const sessionId = `COUNCIL-${Date.now()}`;
const sessionDate = new Date().toLocaleDateString('ar-SA', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
  timeZone: 'Asia/Riyadh'
});

return [{ json: { topic, sessionId, sessionDate, isScheduled, requestedBy: telegramText ? 'صالح (تيليجرام)' : 'جدولة تلقائية' } }];

// =========================================
// تجميع آراء الوكلاء الأربعة واستخلاصها
// =========================================

const allInputs = $input.all();

const extractContent = (item) => {
  try {
    return item.json?.choices?.[0]?.message?.content ||
           item.json?.message?.content ||
           item.json?.response ||
           '(لم يتوفر رأي)';
  } catch { return '(خطأ في استخراج الرأي)'; }
};

const opinions = allInputs.map(extractContent);

// بناء النص الكامل لجلسة المجلس
const councilSession = opinions.join('\n\n---\n\n');

// إعداد بيانات الجلسة للمنسق
const topicData = $('🎯 تحديد الموضوع ومصدر الطلب').item.json;

return [{
  json: {
    topic: topicData.topic,
    sessionId: topicData.sessionId,
    sessionDate: topicData.sessionDate,
    requestedBy: topicData.requestedBy,
    councilSession,
    opinions_count: opinions.length
  }
}];

// استخراج القرار النهائي من رئيس المجلس
const chairDecision = $json?.choices?.[0]?.message?.content ||
                      $json?.message?.content ||
                      $json?.response ||
                      '(تعذر استخراج القرار)';

const sessionData = $('📊 تجميع نص الجلسة').item.json;

// بناء رسالة تيليجرام النهائية
const telegramMessage = [
  `🏛️ *المجلس الاستشاري — قرار الجلسة*`,
  ``,
  `📅 ${sessionData.sessionDate}`,
  `🔖 ${sessionData.sessionId}`,
  `📥 طلب من: ${sessionData.requestedBy}`,
  ``,
  `📋 *الموضوع:*`,
  sessionData.topic,
  ``,
  `─────────────────────`,
  ``,
  chairDecision,
  ``,
  `─────────────────────`,
  ``,
  `هل تعتمد توصية المجلس؟`
].join('\n');

return [{
  json: {
    telegramMessage,
    chairDecision,
    sessionId: sessionData.sessionId,
    topic: sessionData.topic
  }
}];

// حفظ محضر الجلسة في logs/
const fs = require('fs');
const path = require('path');

const sessionData = $('📊 تجميع نص الجلسة').item.json;
const chairDecision = $('📝 صياغة القرار النهائي').item.json.chairDecision;

const record = {
  sessionId: sessionData.sessionId,
  sessionDate: sessionData.sessionDate,
  topic: sessionData.topic,
  requestedBy: sessionData.requestedBy,
  councilOpinions: sessionData.councilSession,
  chairDecision,
  recordedAt: new Date().toISOString()
};

// محاولة الحفظ (يعمل فقط إذا كان /app/logs موجوداً داخل الحاوية)
try {
  const logPath = '/app/logs/advisory_council_sessions.jsonl';
  fs.appendFileSync(logPath, JSON.stringify(record, null, 0) + '\n', 'utf8');
} catch(e) {
  console.log('تنبيه: تعذر حفظ المحضر في logs/ — ' + e.message);
}

return [{ json: { status: 'logged', sessionId: sessionData.sessionId } }];
